 68	  allowResourceEditing: boolean,
 69	  s3Client: S3Commands,
 70	  noobaaObjectBucket: K8sResourceKind,
 71	  refreshTokens: () => void,
 72	  setEmptyBucketResponse: React.Dispatch<
 73	    React.SetStateAction<EmptyBucketResponse>
 74	  >
