 76	  const providerType = s3Client.providerType as S3ProviderType;
 77	  return [
 78	    {
 79	      title: t('Empty bucket'),
 80	      onClick: () =>
 81	        launcher(LazyEmptyBucketModal, {
 82	          isOpen: true,
 83	          extraProps: {
 84	            bucketName,
 85	            s3Client,
 86	            refreshTokens,
 87	            setEmptyBucketResponse,
 88	          },
 89	        }),
 90	    },
 91	    {
 92	      title: t('Delete bucket'),
 93	      onClick: () =>
 94	        launcher(LazyDeleteBucketModal, {
 95	          isOpen: true,
 96	          extraProps: {
 97	            bucketName,
 98	            s3Client,
 99	            launcher,
100	            refreshTokens,
101	            setEmptyBucketResponse,
102	          },
103	        }),
104	    },
105	    ...(allowResourceEditing
