188	const BucketOverview: React.FC<{}> = () => {
189	  const { t } = useCustomTranslation();
190	  const [fresh, triggerRefresh] = useRefresh();
191	
192	  const launcher = useModal();
193	  const navigate = useNavigate();
194	
195	  const { bucketName } = useParams();
196	  const [searchParams] = useSearchParams();
197	
198	  const isAdmin = useFlag(ODF_ADMIN);
199	  const providerType = useProviderType();
200	
201	  const [emptyBucketResponse, setEmptyBucketResponse] =
202	    React.useState<EmptyBucketResponse>({
203	      response: null,
204	      bucketName: '',
205	    });
206	
207	  // if non-empty means we are inside particular folder(s) of a bucket, else just inside a bucket (top-level)
208	  const foldersPath = searchParams.get(PREFIX);
209	
210	  // "isCreatedByOBC" denotes whether bucket is created via OBC or S3 endpoint (will be false if we are inside folder view)
211	  const { isCreatedByOBC, noobaaObjectBucket, isLoading, error } =
212	    useBucketOrigin(bucketName, foldersPath, isAdmin);
213	
214	  const allowResourceEditing = isAdmin && isCreatedByOBC && _.isEmpty(error);
215	
216	  const { breadcrumbs, currentFolder } = React.useMemo(
217	    () => getBreadcrumbs(foldersPath, bucketName, providerType, t),
218	    [foldersPath, bucketName, providerType, t]
219	  );
220	
221	  const navPages: TabPage[] = React.useMemo(
222	    () => [
223	      {
224	        href: 'objects',
225	        title: t('Objects'),
226	        component: ObjectListWithSidebar,
227	      },
228	      ...(!foldersPath
229	        ? [
230	            {
231	              href: 'properties',
232	              title: t('Properties'),
233	              component: BucketDetails,
234	            },
235	            {
236	              href: PERMISSIONS_ROUTE,
237	              title: t('Permissions'),
238	              component: React.lazy(() => import('./PermissionsNav')),
239	            },
240	            {
241	              href: MANAGEMENT_ROUTE,
242	              title: t('Management'),
243	              component: React.lazy(() => import('./ManagementNav')),
244	            },
245	          ]
246	        : []),
247	      ...(allowResourceEditing
248	        ? [
249	            {
250	              href: 'yaml',
251	              title: t('YAML'),
252	              component: CustomYAMLEditor,
253	            },
254	          ]
255	        : []),
256	    ],
257	    [foldersPath, allowResourceEditing, t]
258	  );
259	
260	  const renderActions = (s3Client: S3Commands) => () =>
261	    createBucketActions(
262	      t,
263	      fresh,
264	      triggerRefresh,
265	      foldersPath,
266	      launcher,
267	      navigate,
268	      bucketName,
269	      allowResourceEditing,
270	      s3Client,
271	      noobaaObjectBucket,
272	      setEmptyBucketResponse
273	    );
274	
275	  return (
276	    <S3Provider loading={isLoading}>
277	      <BucketOverviewContent
278	        breadcrumbs={breadcrumbs}
279	        foldersPath={foldersPath}
280	        currentFolder={currentFolder}
281	        isCreatedByOBC={isCreatedByOBC}
282	        noobaaObjectBucket={noobaaObjectBucket}
283	        fresh={fresh}
284	        triggerRefresh={triggerRefresh}
285	        navPages={navPages}
286	        bucketName={bucketName}
287	        actions={renderActions}
288	        launcher={launcher}
289	        emptyBucketResponse={emptyBucketResponse}
290	        setEmptyBucketResponse={setEmptyBucketResponse}
291	      />
292	    </S3Provider>
293	  );
294	};
