296	type BucketOverviewContentProps = {
297	  breadcrumbs: { name: string; path: string }[];
298	  foldersPath: string | null;
299	  currentFolder: string;
300	  isCreatedByOBC: boolean;
301	  fresh: boolean;
302	  triggerRefresh: () => void;
303	  noobaaObjectBucket: K8sResourceKind;
304	  navPages: TabPage[];
305	  bucketName: string;
306	  actions: (s3Client: S3Commands) => () => JSX.Element;
307	  launcher: LaunchModal;
308	  emptyBucketResponse: EmptyBucketResponse;
309	  setEmptyBucketResponse: React.Dispatch<
310	    React.SetStateAction<EmptyBucketResponse>
311	  >;
312	};
313	
314	const BucketOverviewContent: React.FC<BucketOverviewContentProps> = ({
315	  breadcrumbs,
316	  foldersPath,
317	  currentFolder,
318	  isCreatedByOBC,
319	  fresh,
320	  triggerRefresh,
321	  noobaaObjectBucket,
322	  navPages,
323	  bucketName,
324	  actions,
325	  emptyBucketResponse,
326	  setEmptyBucketResponse,
327	}) => {
328	  const { s3Client } = React.useContext(S3Context);
329	
330	  const customData = React.useMemo(
331	    () => ({
332	      fresh,
333	      triggerRefresh,
334	      resource: noobaaObjectBucket,
335	    }),
336	    [fresh, triggerRefresh, noobaaObjectBucket]
337	  );
338	
339	  const providerType = s3Client.providerType as S3ProviderType;
340	
341	  return (
342	    <>
343	      <PageHeading
344	        breadcrumbs={breadcrumbs}
345	        title={
346	          <PageTitle
347	            bucketName={bucketName}
348	            providerType={providerType}
349	            foldersPath={foldersPath}
350	            currentFolder={currentFolder}
351	            isCreatedByOBC={isCreatedByOBC}
352	            noobaaObjectBucket={noobaaObjectBucket}
353	          />
354	        }
355	        actions={actions(s3Client)}
356	        className="pf-v6-u-mt-md"
357	      />
358	      <EmptyBucketAlerts
359	        emptyBucketResponse={emptyBucketResponse}
360	        setEmptyBucketResponse={setEmptyBucketResponse}
361	        triggerRefresh={triggerRefresh}
362	      />
363	      <Tabs id="s3-overview" tabs={navPages} customData={customData} />
364	    </>
365	  );
366	};
367	
368	export default BucketOverview;

